INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00637', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於刑事訴訟法第205條之1與第205條之2之規定，下列敘述何者正確？', '["鑑定人實施刑事訴訟法第205條之1之鑑定，應用檢察官、審判長或受命法官核發之許可書", "司法警察官實施刑事訴訟法第205條之2之強制採取處分，應用檢察官、審判長或受命法官核 發之許可書", "鑑定人因蒐集證據之必要，於被告抗拒時，得違反被告之意思，逕行使用強制力採集被告之血液", "司法警察官因調查犯罪情形之必要，於被告抗拒時，得違反被告之意思，逕行使用強制力採集 被告之血液"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00638', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '甲為精神科的著名資深醫師，亦係某殺人案件之被告乙的精神科主治醫師，多年來定期為乙診治 乙的精神宿疾。檢察官為了解與判斷被告乙長期以來的精神狀態，以之作為起訴論罪與具體求刑 的重要依據之一，乃傳喚甲出庭陳述其過去多年來長期診治乙精神宿疾之狀況。依據刑事訴訟法 之規定與最高法院司法實務之見解，下列敘述何者正確？', '["甲應適用關於鑑定人具結之程序", "甲應適用關於證人具結之程序", "甲係屬不得令其具結之人，毋庸行具結之程序", "甲係屬得拒絕證言權人，毋庸行具結之程序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00639', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察官甲因偵查犯罪之必要，欲對犯罪嫌疑人乙採取口腔內之黏膜組織，以資作為證據資料 使用。關於司法警察官甲對犯罪嫌疑人乙採取口腔內之黏膜組織，依據刑事訴訟法之規定，下列 敘述何者正確？', '["應依據刑事訴訟法第204條之鑑定規定", "應依據刑事訴訟法第205條之1之鑑定規定", "應依據刑事訴訟法第205條之2之鑑定規定採集措施", "應依據刑事訴訟法第213條之勘驗規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00640', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '偵查中之辯護人丙，於司法警察官甲詢問犯罪嫌疑人乙，製作乙之警詢筆錄時的權限，在不違反 偵查不公開原則及不影響偵查秩序者，依據內政部警政署訂頒之「警察偵查犯罪手冊」之規定， 下列敘述何者錯誤？', '["丙得於警詢時以手寫方式札記警詢要點", "丙得於警詢時在場陳述意見", "丙得於警詢完畢後檢閱卷宗資料", "丙得於警詢完畢後協助乙閱覽警詢筆錄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00641', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察官甲因偵查槍擊犯罪之必要，需對犯罪嫌疑人乙所有之自用小客車實施車輛勘察採證。 依據內政部警政署訂頒之「刑事鑑識手冊」，下列敘述何者錯誤？', '["必要時得先逕行實施勘察採證，實施完畢後3日內陳報該管檢察官補行審查", "如出於自願性同意者，無須聲請搜索票或鑑定許可書，但應使用勘察採證同意書", "有急迫情形者，應報請該管檢察官指揮實施勘察採證", "原則上應用搜索票或鑑定許可書"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00642', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察官甲任職於某警察局之刑事警察大隊第一偵查隊，擔任刑事偵查員職務，因偵查網路詐 欺集團犯罪之需要，擬聲請通訊監察該網路詐欺集團之相關共犯。依據通訊保障及監察法與內政 部警政署訂頒之「警察偵查犯罪手冊」規定，下列敘述何者正確？', '["甲辦理通訊監察聲請案件，其聲請因不合法定程序，經法院駁回者，不得聲明不服", "甲辦理通訊監察聲請案件，得由該第一偵查隊隊長從嚴審核決行後，備文逕向該管地方法院提 出聲請", "甲辦理通訊監察聲請案件，得由該第一偵查隊隊長從嚴審核決行後，備文逕向該管檢察署提出 聲請", "甲偵查之網路詐欺集團犯罪，非屬得通訊監察之犯罪，不得聲請通訊監察該網路詐欺集團之相 關共犯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00643', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '犯罪嫌疑人甲涉嫌於高雄市新興區對乙實施強盜犯罪既遂。甲現居住於臺中市中區，平日於桃園 市龜山區工作，因其子女就學需要，乃將其戶籍地設於臺北市中山區。乙現居住於新北市林口區， 平日於基隆市仁愛區工作，戶籍地則設於臺南市麻豆區。乙於案發後向其友人丙哭訴，並在丙的 陪同下，向丙熟識之彰化縣警察局刑事警察大隊報案。依據內政部警政署訂頒之「警察偵查犯罪 手冊」規定，下列敘述何者正確？', '["案件由高雄市政府警察局新興分局管轄", "案件由新北市政府警察局林口分局管轄", "案件由桃園市政府警察局龜山分局管轄", "案件由彰化縣警察局刑事警察大隊管轄"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00644', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察官甲、乙於執行巡邏勤務時發現，丙騎乘機車未熄火而於捷運站出口處臨時停車多時。 甲、乙認為丙見渠等接近時，行跡可疑、神情慌張，且身上散發出濃厚酒味，見狀似欲迅速騎車 離去。甲、乙為防止丙騎車離去，情急下乃舉槍喝阻，命丙立即停車接受檢查，急忙中甲發現丙 車之車前置物籃中有以透明拉鍊袋分裝數小包之可疑白色粉末狀物品，甲乃立即伸手至丙車之車 前置物籃中取得前揭透明拉鏈袋內之白色粉末物品。下列敘述何者最正確？', '["甲伸手進入丙車之車前置物籃中取得透明拉鍊袋內之白色粉末，係屬違法搜索行為", "甲伸手進入丙車之車前置物籃中取得透明拉鍊袋內之白色粉末，係屬附帶搜索行為，且因急迫 情形，得不使用搜索票", "甲伸手進入丙車之車前置物籃中取得透明拉鍊袋內之白色粉末，係屬勘察採證行為，得不使用 搜索票", "甲伸手進入丙車之車前置物籃中取得透明拉鍊袋內之白色粉末，係屬勘察採證行為，且因急迫 情形，得不使用搜索票"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00645', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '某日市民乙至司法警察機關，向執行勤務中之司法警察官甲表示，犯罪行為人丙日前當街於大庭 廣眾，眾目睽睽下，對其辱罵不雅之言詞與舉動，其欲對丙提出公然侮辱罪之告訴。關於司法警 察官甲於受理告訴後之移送遞解，依據內政部警政署訂頒之「警察偵查犯罪手冊」規定，下列敘 述何者正確？', '["全案尚未調查完畢，但乙已向該管檢察官提出告訴者，應將案件移送該管檢察官處理", "全案已調查完畢，犯罪證據仍不明確，但乙堅持提出告訴者，應將案件移送該管檢察官處理", "全案已調查完畢，但證據證明力薄弱，是否構成犯罪顯有疑義者，應將案件移送該管檢察官處理", "全案已調查完畢，認有犯罪嫌疑者，應將案件移送該管檢察官處理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00646', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '甲涉嫌詐欺，A警局以通知書請甲到場說明。請問下列選任或指定辯護人之情形何者不合法？', '["甲已委任某律師為辯護人，並由該律師陪同他進入A警局", "警詢筆錄製作到一半，甲表示要選任辯護人", "甲已表示不需要辯護人，但甲之配偶不放心還是為其選任辯護人到警局", "甲表示其為低收入戶無法選任辯護人，警員遂通知法律扶助機構指派律師到場"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:16+00:00", "source_pdf_sha1": "4035cbc913f5", "answer_pdf_sha1": "c198657ab766", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
